import{_ as e,o as t,c as i,a2 as a}from"./chunks/framework.C69UpXSI.js";const k=JSON.parse('{"title":"MCP (Model Context Protocol)","description":"","frontmatter":{},"headers":[],"relativePath":"en/configuration/mcp.md","filePath":"en/configuration/mcp.md"}'),n={name:"en/configuration/mcp.md"};function o(l,s,r,d,p,h){return t(),i("div",null,[...s[0]||(s[0]=[a(`<h1 id="mcp-model-context-protocol" tabindex="-1">MCP (Model Context Protocol) <a class="header-anchor" href="#mcp-model-context-protocol" aria-label="Permalink to &quot;MCP (Model Context Protocol)&quot;">​</a></h1><p>TurboDev supports connecting external tool servers via the <a href="https://modelcontextprotocol.io" target="_blank" rel="noreferrer">Model Context Protocol</a> (MCP) — an open standard adopted by Claude Code, VS Code Copilot, Cursor, ChatGPT, and others. A single MCP server works across all of them, including TurboDev.</p><p><strong>V1 scope</strong>: stdio transport only, tools primitive only, project-level config only.</p><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><p>Create <code>.turbodev/mcp.json</code> in your project root (Claude Desktop-compatible format):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;filesystem&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;npx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-y&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@modelcontextprotocol/server-filesystem&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/Users/me/projects&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Launch TurboDev. The server is spawned as a child process via stdio, the MCP <code>initialize</code> handshake is performed, and each tool the server exposes is registered with a prefixed name (<code>mcp__&lt;server&gt;__&lt;tool&gt;</code>) so the LLM can invoke it like a native tool.</p><p>Type <code>/mcp</code> to verify the connection:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MCP Servers (1 connected, 5 tools total):</span></span>
<span class="line"><span>  ✓ filesystem            5 tools    connected</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Use /mcp reload to re-read .turbodev/mcp.json and reconnect.</span></span></code></pre></div><h2 id="configuration-reference" tabindex="-1">Configuration Reference <a class="header-anchor" href="#configuration-reference" aria-label="Permalink to &quot;Configuration Reference&quot;">​</a></h2><p>The config file lives at <code>&lt;project&gt;/.turbodev/mcp.json</code> and follows the Claude Desktop <code>mcpServers</code> schema byte-for-byte — you can copy configs across tools.</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>command</code></td><td><code>string</code></td><td>yes</td><td>Executable to spawn (resolved via <code>PATH</code>, never through a shell).</td></tr><tr><td><code>args</code></td><td><code>string[]</code></td><td>no</td><td>Arguments passed to the command.</td></tr><tr><td><code>env</code></td><td><code>Record&lt;string, string&gt;</code></td><td>no</td><td>Environment variables for the child process. Supports <code>$VAR</code>, <code>\${VAR}</code>, and leading <code>~</code> expansion.</td></tr></tbody></table><p>Example with all fields:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;github&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;npx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-y&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@modelcontextprotocol/server-github&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;env&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;GITHUB_TOKEN&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$GITHUB_TOKEN&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;LOG_DIR&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;~/logs/mcp&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Unknown fields on a server entry are silently dropped (forward-compatible). Invalid entries are skipped with a logged warning; valid entries in the same file still load.</p><h2 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>/mcp</code></td><td>List all servers with status (<code>connected</code>/<code>error</code>/<code>disabled</code>), tool counts, and error messages.</td></tr><tr><td><code>/mcp reload</code></td><td>Re-read <code>.turbodev/mcp.json</code>, disconnect removed/changed servers, connect new ones. Unchanged servers are left alone (no churn).</td></tr></tbody></table><p>The status bar shows <code>MCP:N</code> (magenta) when N servers are connected.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>MCP tools default to <strong><code>ask</code></strong> — the user must approve the first invocation from each server. Override per-server in an agent Markdown file:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">my-agent</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">permission</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  mcp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">filesystem</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">allow</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">github</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ask</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><p>Or globally for all MCP servers:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">permission</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  mcp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">allow</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # allow every MCP tool without prompting</span></span></code></pre></div><p>Resolution order: per-server map entry → global string → default <code>ask</code>. Disabling a specific tool via <code>tools: { &quot;mcp__filesystem__read_file&quot;: false }</code> still works and takes precedence (returns <code>deny</code>).</p><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><ul><li><strong>No shell</strong>: <code>command</code>/<code>args</code> are passed to <code>child_process.spawn</code> directly, never through a shell — no shell injection is possible.</li><li><strong>Env expansion is local</strong>: <code>$VAR</code> and <code>~</code> are expanded by TurboDev before spawning; the server receives the resolved values.</li><li><strong>Secrets are never logged</strong>: if a config entry is invalid, only the server <em>name</em> is logged, never the command, args, or env values.</li><li><strong>Default <code>ask</code></strong>: external tools cannot execute without explicit user opt-in.</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Cause / Fix</th></tr></thead><tbody><tr><td><code>✗ server error ENOENT</code></td><td>The <code>command</code> was not found in <code>PATH</code>. Verify the executable is installed (e.g. <code>npx -y @modelcontextprotocol/server-filesystem --help</code> works outside TurboDev).</td></tr><tr><td><code>✗ server error MCP connect timeout (10s)</code></td><td>Server spawned but never answered the <code>initialize</code> handshake. Check the server&#39;s stderr output in the console.</td></tr><tr><td>Server disappears from <code>/mcp</code> after reload</td><td>The entry was removed from <code>.turbodev/mcp.json</code> or failed validation — check the logged warning.</td></tr><tr><td>Permission denied on every call</td><td>The agent&#39;s <code>permission.mcp</code> is set to <code>deny</code>, or the server name in <code>permission.mcp</code> doesn&#39;t match the key in <code>mcpServers</code>.</td></tr><tr><td>Tool call returns <code>Cancelled by user</code></td><td>You pressed Escape while the call was in flight. Re-issue the request to retry.</td></tr></tbody></table><h2 id="limitations-v1" tabindex="-1">Limitations (V1) <a class="header-anchor" href="#limitations-v1" aria-label="Permalink to &quot;Limitations (V1)&quot;">​</a></h2><ul><li><strong>stdio transport only</strong> — no remote HTTP servers (Phase 2)</li><li><strong>Tools primitive only</strong> — no resources, prompts, sampling, or elicitation (Phase 2/3)</li><li><strong>Project-level config only</strong> — no global <code>~/.config/turbodev/mcp.json</code> (Phase 2)</li><li><strong>No <code>notifications/tools/list_changed</code></strong> — use <code>/mcp reload</code> to pick up server-side tool changes</li><li><strong>No OAuth</strong> — env-var-based auth only</li></ul><h2 id="discovering-servers" tabindex="-1">Discovering Servers <a class="header-anchor" href="#discovering-servers" aria-label="Permalink to &quot;Discovering Servers&quot;">​</a></h2><p>Browse the official reference servers at <a href="https://github.com/modelcontextprotocol/servers" target="_blank" rel="noreferrer">github.com/modelcontextprotocol/servers</a> and the community catalog at <a href="https://modelcontextprotocol.io" target="_blank" rel="noreferrer">modelcontextprotocol.io</a>. Any stdio-based server that follows the MCP spec will work with TurboDev.</p>`,32)])])}const g=e(n,[["render",o]]);export{k as __pageData,g as default};
